//  BAD PERFORMANCE: Changing 'margin' triggers a full Layout/Reflow.
// The browser has to recalculate the size/position of EVERY element on the page.
element.style.marginLeft = '100px'; 

//  GREAT PERFORMANCE: Changing 'transform' skips Layout and Paint!
// It happens entirely on the GPU (Graphics Card) in a separate 'Composite' layer.
element.style.transform = 'translateX(100px)';
